var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"어떻게 된 거죠? 그림자가… 왜 놈을 갑자기 공격하고 있는 겁니까?","JPN":"どういうことですか？　シャドウが……なんでいきなりやつを攻撃してるんですか？","ENG":"What's going on? The Shadow... Why's it attacking her all of a sudden?","TWN":"怎麼回事？暗影…爲什麼突然襲擊她？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그림자는 침식체와 마찬가지로 동족의식 같은 게 없어.","JPN":"シャドウは侵食体と同じく、同族意識なんてものはない。","ENG":"Shadows and C.O.s have no sense of kinship.","TWN":"暗影和侵蝕體一樣，沒有同族意識。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"단지 생전 가장 강했던 집착을 원동력으로 움직이는 것뿐이야.","JPN":"ただ生前もっとも強かった執着を原動力にして動いてるだけだ。","ENG":"Their actions are motivated by their most intense obsession from their previous life.","TWN":"暗影的動力就是生前最強烈的執念。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"그렇다는 건, 저 그림자가 움직이는 이유도…","JPN":"それじゃあ、あのシャドウが動いてる理由も……","ENG":"Then, that Shadow is also acting on...","TWN":"這麼說來，那個暗影之所以會行動…"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"쿨럭……! 뭐가 이렇게 무식하게 세……?","JPN":"ガハッ……！　なんでこんなに強いの……？","ENG":"Kuh...! Why are you so stupidly strong...?","TWN":"咳咳……！還真厲害………？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그림자를… 막아.","JPN":"シャドウを……食い止めろ。","ENG":"Stop... Shadow.","TWN":"抵擋… 暗影。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"그림자를… 죽여.","JPN":"シャドウを……殺せ。","ENG":"Kill... Shadow.","TWN":"殺掉… 暗影。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"아하하핫, 큐리안. 네가 강하다는 건 알겠는데 말이야.","JPN":"あはははっ、キュリアン。あんたが強いってのはわかるけどね。","ENG":"Ah ha ha hah! I get that you're strong, Curian...","TWN":"哈哈哈哈，庫里安，我知道你很強。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"침식체로서 넌 아직 알 껍질도 못 깬 풋내기라고. 내 연주를 거스를 순 없어.","JPN":"侵食体としてのあんたはまだ殻も破れないヒヨコなの。私の演奏に逆らうことなんてできないわ。","ENG":"But you're newborn Shadow. You can't disobey my performance.","TWN":"但作爲侵蝕體，你可是還沒破繭而出的新手，別想反抗我的演奏。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"……안 돼! 모두 도망쳐!","JPN":"……ダメ！　みんな逃げて！","ENG":"...No! Fall back!","TWN":"……不行！大家快逃！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"으아아악!!!","JPN":"うわああっ！！","ENG":"AAAGH!!","TWN":"呃啊啊啊！！！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"2격대가… 순식간에 전멸하다니…","JPN":"第2撃隊が……一瞬で全滅するなんて……","ENG":"W-where did... the 2nd strike unit go?","TWN":"第2小隊…瞬間全數陣亡…"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"뭐… 뭐지? 눈에 보이지도 않았어. 왜 갑자기 저렇게 빨라진 거야?","JPN":"な……何だ？　目に見えなかったぞ。なんでいきなりあんなに速くなったんだ？","ENG":"H-huh? What just happened? Why did it suddenly picked up speed?","TWN":"什…什麼？我都看不到，怎麼突然變得那麼快？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"저 녀석이 제어하기 시작한 것 같군. 우리 눈에 헛것을 씌워서 가지고 놀았던 것처럼.","JPN":"あいつが制御しはじめたようだな。私たちの目に幻覚を見せながら遊んでたように。","ENG":"She's started controlling it. Just like she did when she was toying with us.","TWN":"她似乎開始控制，我們就像她的玩物一樣。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"이거…… 저희가 이길 가능성은 있는 겁니까?","JPN":"これ……俺らが勝つ可能性はあるんですか？","ENG":"This... is it even possible to win against that thing?","TWN":"這…… 我們有贏的可能嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"……미안해. 녀석이 다른 그림자까지 끌어들이게 될 거라고는 상정 못 했어.","JPN":"……すまない。あいつが他のシャドウまで巻き込むとは予想していなかった。","ENG":"...I'm sorry. I didn't expect her to bring in another Shadow.","TWN":"……對不起，我沒想到那傢伙還會把其他暗影都扯進來。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}}]`);export{e as default};